  // remainingCap is not yet exercised by any test; its behaviour is driven by
  // the "claim — cap" tests still to come, so it stays optional for now.
  remainingCap?: number;
}

const DEDUCTIBLE = 100;

export function claim(input: ClaimInput): ClaimResult {
  const payout = input.incident.damages.reduce(
    (total, damage) => total + (damage.amount - DEDUCTIBLE),
    0,
  );
  return { payout };
}

